{
  "verses": [
    {
      "n": 30,
      "column": "left",
      "text": "Un Mibsams/ Mismus/ \nun Dunnis/ Musus/ Adads un \nTemus.\n"
    },
    {
      "n": 31,
      "column": "left",
      "text": "Jeturs/ Nawis/ un Red- \nmus. Schee bija Ismaëta \nBehrni.\n"
    },
    {
      "n": 32,
      "column": "left",
      "text": "Un Returas/ Ahbräama \nleekas Geewas Behrni/ ta dsein- \ndeja Sinirami/ un Jeksami/ un \nMedani/ un Midijana/ un Jes- \nbaku/ un Suii. Un Joksana \nBehrni bija: Sebus un Dedans.\n"
    },
    {
      "n": 33,
      "column": "left",
      "text": "Un Midijana Behrni bi- \nja: Eepus/ un Eewers/ un A- \nnoks/ un Abtdus un Eldaus. \nSchee wiſch bija Returas Behrni.\n"
    },
    {
      "n": 34,
      "column": "left",
      "text": "Un Ahbräams dseindi- \nnoja Ihsäätu: Ihsäätka Behrni \nbija Eesaws un Israëls.\n"
    },
    {
      "n": 35,
      "column": "left",
      "text": "Eesawa Behrnt bija: Ee- \nliwas/ Regnels/ Jeńs un Jaë- \nlams/ un Korus.\n"
    },
    {
      "n": 36,
      "column": "left",
      "text": "Eeliwasa Behrni bija: \nTeemans/ un Omars/ Zepus un \nGaëtans/ Kenas/ un Timnas/ \nun Amaleks.\n"
    },
    {
      "n": 37,
      "column": "left",
      "text": "Regneſka Behrni bija: \nNaäts/ Serus/ Sammus un \nMius.\n"
    },
    {
      "n": 38,
      "column": "left",
      "text": "Un Seira Behrni bija: \nLotans un Sobals/ un Zibeans/ \nun Anus/ un Disons/ un Ezers/ \nun Disans.\n"
    },
    {
      "n": 39,
      "column": "left",
      "text": "Un Lotana Behrni bija: \nOrus/ un Omains/ un Lotana \nMahfa bija Timna.\n"
    },
    {
      "n": 40,
      "column": "left",
      "text": "Sobala Behrni bija: \nAlijans/ un Manaäts/ un Ebate/ \nSevus un Onans. Un Zibe- \nna Behrni bija: Ajus un Anus.\n"
    },
    {
      "n": 41,
      "column": "right",
      "text": "Anns Behrnt bija: Di- \nsons. Un Disona Behrnt bija/ \nAmrans/ un Eßans/ un Je- \ntrans/ un Krans.\n"
    },
    {
      "n": 42,
      "column": "right",
      "text": "Ezeka Behrni bija: Bi- \nlans/ un Saëwans/ Jaëkans. \nDisana Behrni bija uz un Arans.\n"
    },
    {
      "n": 43,
      "column": "right",
      "text": "Un schee irr tee Kehnizi/ \nkas Eedoma Semmē waldijschi/ \npirus Kehnizi pahr Israëla \nBehrneem waldtia. Belus/ \nBeera Dehls/ un winna Pils- \nsahta Wahrsds bija Dinaba.\n"
    },
    {
      "n": 44,
      "column": "right",
      "text": "Un Belus nomirre/ un \nwinna Weeta tappe par Kehni- \nznu Jobabs Sera Dehls no \nBazras.\n"
    },
    {
      "n": 45,
      "column": "right",
      "text": "Un Jobabs nomirre/ un \nUsans no tahs Temaniteru \nSemmes tappe par Kehnizu \nwinna Weeta.\n"
    },
    {
      "n": 46,
      "column": "right",
      "text": "Un Usans nomirre/ un \nAdads Bedada Dehls tappe par \nKehnizu winna Weeta/ kas tohs \nMidijaniterus Moaba Lauta \nkaue/ un winna Bilssahta \nWahrsds bija Awits.\n"
    },
    {
      "n": 47,
      "column": "right",
      "text": "Un Adads nomirre/ un \nSamlus no Masrekas tappe par \nKehnizu winna Weeta.\n"
    },
    {
      "n": 48,
      "column": "right",
      "text": "Un kad Samlus nomir- \nre/ tad tappe Sauls no Reko- \nbota pee tahs Uppes par Kehni- \nnu winna Weeta.\n"
    },
    {
      "n": 49,
      "column": "right",
      "text": "Un kad Sauls nomirre/ \ntad tappe Baäl-Anans Akbora \nDehls par Kehnizu winna \nWeeta.\n"
    },
    {
      "n": 50,
      "column": "right",
      "text": "Un kad Baäl-Anans no- \nmirre/ tad tappe Adads par Keh- \n"
    }
  ],
